code = """import json
import re

# Access the funding data from the stored variable
funding_data = var_functions.query_db_4

print(f"Found {len(funding_data)} funding records")

# Create a mapping from cleaned project names to funding info
funding_map = {}
for record in funding_data:
    project_name = record['Project_Name']
    # Clean the project name by removing suffixes for matching
    clean_name = re.sub(r'\s*\([^)]*\)\s*$', '', project_name).strip()
    if clean_name not in funding_map:
        funding_map[clean_name] = []
    funding_map[clean_name].append({
        'Funding_ID': record['Funding_ID'],
        'Funding_Source': record['Funding_Source'],
        'Amount': record['Amount'],
        'Full_Project_Name': project_name
    })

print(f"Mapped {len(funding_map)} unique project names")

# Check some examples
print("Sample projects:")
for i, (name, funds) in enumerate(list(funding_map.items())[:10]):
    print(f"  {name}: {len(funds)} funding records")

# Save the funding map for later use
with open('/tmp/funding_map.json', 'w') as f:
    json.dump(funding_map, f, indent=2)

print("__RESULT__:")
print(json.dumps({"status": "success", "project_count": len(funding_map)}))"""

